diff --git a/test/validate-options.test.js b/test/validate-options.test.js
new file mode 100644
index 0000000..c7bdf18
--- /dev/null
+++ b/test/validate-options.test.js
@@ -0,0 +1,201 @@
+import CompressionPlugin from '../src';
+
+it('validation', () => {
+  /* eslint-disable no-new */
+  expect(() => {
+    new CompressionPlugin({ test: /foo/ });
+  }).not.toThrow();
+
+  expect(() => {
+    new CompressionPlugin({ test: 'foo' });
+  }).not.toThrow();
+
+  expect(() => {
+    new CompressionPlugin({ test: [/foo/] });
+  }).not.toThrow();
+
+  expect(() => {
+    new CompressionPlugin({ test: [/foo/, /bar/] });
+  }).not.toThrow();
+
+  expect(() => {
+    new CompressionPlugin({ test: ['foo', 'bar'] });
+  }).not.toThrow();
+
+  expect(() => {
+    new CompressionPlugin({ test: [/foo/, 'bar'] });
+  }).not.toThrow();
+
+  expect(() => {
+    new CompressionPlugin({ test: true });
+  }).toThrowErrorMatchingSnapshot();
+
+  expect(() => {
+    new CompressionPlugin({ test: [true] });
+  }).toThrowErrorMatchingSnapshot();
+
+  expect(() => {
+    new CompressionPlugin({ test: [/foo/, 'foo', true] });
+  }).toThrowErrorMatchingSnapshot();
+
+  expect(() => {
+    new CompressionPlugin({ include: /foo/ });
+  }).not.toThrow();
+
+  expect(() => {
+    new CompressionPlugin({ include: 'foo' });
+  }).not.toThrow();
+
+  expect(() => {
+    new CompressionPlugin({ include: [/foo/] });
+  }).not.toThrow();
+
+  expect(() => {
+    new CompressionPlugin({ include: [/foo/, /bar/] });
+  }).not.toThrow();
+
+  expect(() => {
+    new CompressionPlugin({ include: ['foo', 'bar'] });
+  }).not.toThrow();
+
+  expect(() => {
+    new CompressionPlugin({ include: [/foo/, 'bar'] });
+  }).not.toThrow();
+
+  expect(() => {
+    new CompressionPlugin({ include: true });
+  }).toThrowErrorMatchingSnapshot();
+
+  expect(() => {
+    new CompressionPlugin({ include: [true] });
+  }).toThrowErrorMatchingSnapshot();
+
+  expect(() => {
+    new CompressionPlugin({ include: [/foo/, 'foo', true] });
+  }).toThrowErrorMatchingSnapshot();
+
+  expect(() => {
+    new CompressionPlugin({ exclude: /foo/ });
+  }).not.toThrow();
+
+  expect(() => {
