+  }).not.toThrow();
+
+  expect(() => {
+    new CompressionPlugin({ deleteOriginalAssets: 'true' });
+  }).toThrowErrorMatchingSnapshot();
+
+  expect(() => {
+    new CompressionPlugin({ unknown: true });
